import{_ as a,o as e,c as r,ag as l}from"./chunks/framework.CNG7EpJN.js";const p=JSON.parse('{"title":"セルフオーダー画面","description":"","frontmatter":{"title":"セルフオーダー画面"},"headers":[],"relativePath":"tenant/17-customer.md","filePath":"tenant/17-customer.md"}'),o={name:"tenant/17-customer.md"};function i(n,t,s,d,h,c){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="_17-セルフオーダー画面" tabindex="-1">17. セルフオーダー画面 <a class="header-anchor" href="#_17-セルフオーダー画面" aria-label="Permalink to &quot;17. セルフオーダー画面&quot;">​</a></h1><p>セルフオーダー画面は、お客様がテーブルQRコードから開く注文画面です。店舗スタッフは、表示内容と注文の流れを理解しておくと問い合わせ対応がしやすくなります。</p><h2 id="お客様の注文手順" tabindex="-1">お客様の注文手順 <a class="header-anchor" href="#お客様の注文手順" aria-label="Permalink to &quot;お客様の注文手順&quot;">​</a></h2><ol><li>テーブルのQRコードをスマートフォンで読み取ります。</li><li>メニューを選び、数量やオプションを選択してカートに入れます。</li><li>カート内容を確認します。</li><li><strong>ゲスト名（任意）</strong>: 注文送信前に、注文者の名前（ニックネーム等）を入力できます。入力すると、注文履歴やレジ画面で誰の注文かが判別しやすくなります。</li><li>注文を送信します。</li><li>必要に応じてスタッフ呼び出しやAIウェイターを利用します。</li></ol><h2 id="注文履歴とセルフ会計" tabindex="-1">注文履歴とセルフ会計 <a class="header-anchor" href="#注文履歴とセルフ会計" aria-label="Permalink to &quot;注文履歴とセルフ会計&quot;">​</a></h2><h3 id="注文履歴の二層表示" tabindex="-1">注文履歴の二層表示 <a class="header-anchor" href="#注文履歴の二層表示" aria-label="Permalink to &quot;注文履歴の二層表示&quot;">​</a></h3><p>注文履歴画面では、以下の2つのセクションに分かれて表示されます。</p><ul><li><strong>未払い注文</strong>: 今回の滞在でまだお会計が済んでいない注文です。</li><li><strong>会計済履歴</strong>: すでにお支払いが完了した過去の注文です。</li></ul><h3 id="ゲスト名-任意入力" tabindex="-1">ゲスト名（任意入力） <a class="header-anchor" href="#ゲスト名-任意入力" aria-label="Permalink to &quot;ゲスト名（任意入力）&quot;">​</a></h3><p>カートモーダルで、注文送信前に「ゲスト名」を入力できます。入力した名前は以下の場所で利用され、自分や同席者の注文を区別しやすくなります。</p><ul><li><strong>注文トラッカー</strong>: 誰が何を注文したかを確認。</li><li><strong>注文履歴</strong>: 過去の注文を名前で整理。</li><li><strong>セルフ会計画面</strong>: 支払うべき注文の確認。</li></ul><h3 id="個人負担目安-割り勘計算" tabindex="-1">個人負担目安（割り勘計算） <a class="header-anchor" href="#個人負担目安-割り勘計算" aria-label="Permalink to &quot;個人負担目安（割り勘計算）&quot;">​</a></h3><p>お会計前に、卓全体の合計金額をどのように分担するかを「手入力」でシミュレーションできる計算ツールです。以下の3つのモードから選べます。</p><ul><li><strong>均等に切り上げ</strong>: 合計金額を人数で割り、端数を切り上げた「一人あたりの支払額」を表示します。</li><li><strong>一人が端数を負担</strong>: 一人あたりの金額を指定し、残りの「端数を含めた金額」を特定の一人が支払う目安を表示します。</li><li><strong>自分の分 ＋ 残りを人数割り</strong>: 自分の支払額を手入力し、残りの金額を同席人数で割った目安を表示します。</li></ul><p>::: note この計算機能は入力の手助けをするためのものであり、<code>guest_alias</code> と連動した自動計算や、品目を選んでの個別決済を行うものではありません。 :::</p><div class="warning custom-block"><p class="custom-block-title">決済の制限事項</p><p>セルフ決済（Stripe Checkout）は、<strong>「テーブル全体の合計金額を一括で支払う」</strong> 仕組みです。特定の商品だけを選んで支払う「品目別の個別決済」には対応していません。厳密な個別会計が必要な場合は、店舗のレジスタッフへお申し付けください。</p></div><h3 id="会計後の継続注文" tabindex="-1">会計後の継続注文 <a class="header-anchor" href="#会計後の継続注文" aria-label="Permalink to &quot;会計後の継続注文&quot;">​</a></h3><p>セルフ決済が完了した後、画面に「続けて注文する」ボタンが表示されます。これを利用すると、同じテーブルセッションを維持したまま、追加の注文（デザートや飲み物など）をスムーズに行うことができます。</p><h2 id="aiウェイター" tabindex="-1">AIウェイター <a class="header-anchor" href="#aiウェイター" aria-label="Permalink to &quot;AIウェイター&quot;">​</a></h2><p>お客様はメニューについて質問できます。アレルギー、提供可否、価格など重要な内容は、店舗スタッフが最終確認してください。</p><h2 id="スタッフ呼び出し" tabindex="-1">スタッフ呼び出し <a class="header-anchor" href="#スタッフ呼び出し" aria-label="Permalink to &quot;スタッフ呼び出し&quot;">​</a></h2><p>お客様から呼び出しが入った場合は、店舗のルールに従って対応してください。呼び出し内容が分かる場合は、先に内容を確認してから向かうとスムーズです。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>メニューが表示されない</td><td>QRコード、店舗設定、メニュー公開状態を確認してください。</td></tr><tr><td>注文できない</td><td>Wi-Fi、売り切れ状態、テーブル開放状態を確認してください。</td></tr><tr><td>表示言語が違う</td><td>画面上の言語切替を確認してください。</td></tr><tr><td>金額が違う</td><td>商品価格、オプション、税区分を確認してください。</td></tr></tbody></table>',24)])])}const b=a(o,[["render",i]]);export{p as __pageData,b as default};
